begin;
insert into stories (id, course_id, cefr_level, order_index, title, subtitle, emoji, intro, est_seconds, segments, glossary, questions) values
('a6cf8f45-3193-501f-a12e-97d7aeaccc16'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B1',2,$p$L'appartement de Karim$p$,$p$Karim busca un piso en Lyon y va a visitar uno con la propietaria.$p$,$p$🔑$p$,$p$Karim acaba de encontrar trabajo en Lyon y necesita mudarse. Lee y escucha cómo visita un apartamento que ha encontrado en internet.$p$,56,$j$[{"en": "Quand j'ai trouvé mon nouveau travail à Lyon, j'étais très content, mais je devais trouver un appartement rapidement.", "es": "Cuando encontré mi nuevo trabajo en Lyon, estaba muy contento, pero tenía que encontrar un apartamento rápidamente.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/a6cf8f45-3193-501f-a12e-97d7aeaccc16-0.mp3"}, {"en": "J'ai cherché pendant des semaines sur internet, et hier, j'ai enfin trouvé une annonce qui me semblait parfaite.", "es": "Busqué durante semanas en internet, y ayer por fin encontré un anuncio que me parecía perfecto.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/a6cf8f45-3193-501f-a12e-97d7aeaccc16-1.mp3"}, {"en": "C'est un petit appartement dont le loyer n'est pas trop cher, dans un quartier où il y a beaucoup de commerces.", "es": "Es un apartamento pequeño cuyo alquiler no es demasiado caro, en un barrio donde hay muchos comercios.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/a6cf8f45-3193-501f-a12e-97d7aeaccc16-2.mp3"}, {"en": "La propriétaire, qui s'appelle Madame Rousseau, m'a accueilli et me l'a fait visiter avec le sourire.", "es": "La propietaria, que se llama la señora Rousseau, me recibió y me lo enseñó con una sonrisa.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/a6cf8f45-3193-501f-a12e-97d7aeaccc16-3.mp3"}, {"en": "« Si vous prenez cet appartement, vous devrez signer le bail et me donner une caution », m'a-t-elle expliqué.", "es": "«Si toma este apartamento, tendrá que firmar el contrato y darme una fianza», me explicó.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/a6cf8f45-3193-501f-a12e-97d7aeaccc16-4.mp3"}, {"en": "Je lui ai répondu qu'il fallait que je réfléchisse, car je voudrais comparer avec un autre logement avant de décider.", "es": "Le respondí que hacía falta que lo pensara, porque querría comparar con otra vivienda antes de decidir.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/a6cf8f45-3193-501f-a12e-97d7aeaccc16-5.mp3"}, {"en": "Finalement, l'appartement m'a beaucoup plu, et si tout se passe bien, je pense que je déménagerai le mois prochain.", "es": "Al final, el apartamento me gustó mucho, y si todo va bien, creo que me mudaré el mes que viene.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/a6cf8f45-3193-501f-a12e-97d7aeaccc16-6.mp3"}]$j$::jsonb,$j$[{"word": "une annonce", "translation": "un anuncio"}, {"word": "le loyer", "translation": "el alquiler"}, {"word": "le bail", "translation": "el contrato de arrendamiento"}, {"word": "la caution", "translation": "la fianza / el depósito"}, {"word": "il faut que je réfléchisse", "translation": "hace falta que lo piense"}, {"word": "déménager", "translation": "mudarse"}]$j$::jsonb,$j$[{"type": "multiple_choice", "skill": "reading", "prompt": "¿Por qué Karim necesitaba encontrar un apartamento rápidamente?", "payload": {"options": ["porque encontró un nuevo trabajo en Lyon", "porque quería vivir cerca del mar", "porque su familia venía a visitarlo"]}, "difficulty": 0.5, "correct_answer": {"value": "porque encontró un nuevo trabajo en Lyon"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Cómo describe el barrio del apartamento?", "payload": {"options": ["un barrio con muchos comercios", "un barrio muy tranquilo y aislado", "un barrio lejos del centro"]}, "difficulty": 0.5, "correct_answer": {"value": "un barrio con muchos comercios"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Quién es la señora Rousseau?", "payload": {"options": ["la propietaria del apartamento", "una vecina del edificio", "la jefa de Karim"]}, "difficulty": 0.5, "correct_answer": {"value": "la propietaria del apartamento"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "Según la propietaria, ¿qué tendrá que hacer Karim si toma el apartamento?", "payload": {"options": ["firmar el contrato y dar una fianza", "pagar un año por adelantado", "pintar las paredes él mismo"]}, "difficulty": 0.5, "correct_answer": {"value": "firmar el contrato y dar una fianza"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Por qué Karim no decide en ese momento?", "payload": {"options": ["quiere comparar con otra vivienda antes", "el apartamento no le gustó nada", "el alquiler era demasiado caro"]}, "difficulty": 0.5, "correct_answer": {"value": "quiere comparar con otra vivienda antes"}}]$j$::jsonb),
('4e7df89e-e299-5a32-aab1-81fb611fe1f6'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,'B1',2,$p$Il colloquio di Giulia$p$,$p$Giulia viaja a Milán para una entrevista de trabajo y un imprevisto lo cambia todo.$p$,$p$🚆$p$,$p$Giulia tiene una entrevista importante en Milán. Un retraso del tren pondrá a prueba su calma... y su italiano.$p$,56,$j$[{"en": "Quella mattina Giulia si è svegliata presto perché aveva un colloquio di lavoro molto importante a Milano. Mentre faceva colazione, ripassava le risposte che avrebbe dato al direttore.", "es": "Aquella mañana Giulia se despertó temprano porque tenía una entrevista de trabajo muy importante en Milán. Mientras desayunaba, repasaba las respuestas que le daría al director.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/4e7df89e-e299-5a32-aab1-81fb611fe1f6-0.mp3"}, {"en": "Il treno che doveva prendere partiva alle otto, ma quando è arrivata in stazione, un annuncio ha detto che c'era un ritardo di quaranta minuti. «Non ci posso credere», ha pensato, guardando l'orologio con ansia.", "es": "El tren que debía tomar salía a las ocho, pero cuando llegó a la estación, un anuncio dijo que había un retraso de cuarenta minutos. «No me lo puedo creer», pensó, mirando el reloj con ansiedad.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/4e7df89e-e299-5a32-aab1-81fb611fe1f6-1.mp3"}, {"en": "Ha telefonato subito all'azienda per avvisare. «Penso che arriverò con un po' di ritardo, mi dispiace davvero», ha spiegato. La segretaria, gentile, le ha risposto che non c'era problema e che il direttore l'avrebbe aspettata.", "es": "Llamó enseguida a la empresa para avisar. «Creo que llegaré con un poco de retraso, lo siento de verdad», explicó. La secretaria, amable, le respondió que no había problema y que el director la esperaría.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/4e7df89e-e299-5a32-aab1-81fb611fe1f6-2.mp3"}, {"en": "Sul treno Giulia ha conosciuto un signore anziano di cui non dimenticherà mai il consiglio. «Se fossi in lei, non mi preoccuperei troppo», le ha detto sorridendo. «Un ritardo può capitare a tutti; ciò che conta è come reagisci.»", "es": "En el tren Giulia conoció a un señor mayor de cuyo consejo nunca se olvidará. «Yo que usted, no me preocuparía demasiado», le dijo sonriendo. «Un retraso le puede pasar a cualquiera; lo que cuenta es cómo reaccionas.»", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/4e7df89e-e299-5a32-aab1-81fb611fe1f6-3.mp3"}, {"en": "Quando finalmente è arrivata, si è scusata di nuovo, ma il direttore ne ha riso: «Anch'io una volta ho perso un aereo per un colloquio! L'importante è che lei sia qui adesso.» Quelle parole l'hanno tranquillizzata subito.", "es": "Cuando por fin llegó, se disculpó de nuevo, pero el director se rió de ello: «¡Yo también una vez perdí un avión para una entrevista! Lo importante es que usted esté aquí ahora.» Aquellas palabras la tranquilizaron enseguida.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/4e7df89e-e299-5a32-aab1-81fb611fe1f6-4.mp3"}, {"en": "Il colloquio è andato molto meglio di quanto Giulia si aspettasse. Ha parlato con sicurezza dei progetti che aveva seguito e delle lingue che conosceva. Sentiva che, nonostante il ritardo, stava facendo una buona impressione.", "es": "La entrevista fue mucho mejor de lo que Giulia esperaba. Habló con seguridad de los proyectos que había llevado y de los idiomas que conocía. Sentía que, a pesar del retraso, estaba causando una buena impresión.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/4e7df89e-e299-5a32-aab1-81fb611fe1f6-5.mp3"}, {"en": "Due settimane dopo ha ricevuto una mail: era stata assunta. Giulia ha sorriso e ha pensato al signore del treno. Aveva ragione: se avesse perso la calma quella mattina, forse tutto sarebbe andato diversamente.", "es": "Dos semanas después recibió un correo: había sido contratada. Giulia sonrió y pensó en el señor del tren. Tenía razón: si hubiera perdido la calma aquella mañana, quizás todo habría salido de otra manera.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/4e7df89e-e299-5a32-aab1-81fb611fe1f6-6.mp3"}]$j$::jsonb,$j$[{"word": "il colloquio di lavoro", "translation": "la entrevista de trabajo"}, {"word": "il ritardo", "translation": "el retraso"}, {"word": "avvisare", "translation": "avisar"}, {"word": "di cui", "translation": "del cual / de quien"}, {"word": "essere assunto/a", "translation": "ser contratado/a"}, {"word": "nonostante", "translation": "a pesar de"}]$j$::jsonb,$j$[{"type": "multiple_choice", "skill": "reading", "prompt": "¿Por qué se despertó temprano Giulia esa mañana?", "payload": {"options": ["Porque tenía una entrevista de trabajo en Milán", "Porque quería visitar a un amigo", "Porque perdía siempre el tren"]}, "difficulty": 0.5, "correct_answer": {"value": "Porque tenía una entrevista de trabajo en Milán"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Qué imprevisto ocurrió en la estación?", "payload": {"options": ["El tren tenía un retraso de cuarenta minutos", "El tren fue cancelado", "Perdió la cartera"]}, "difficulty": 0.5, "correct_answer": {"value": "El tren tenía un retraso de cuarenta minutos"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Qué consejo le dio el señor mayor del tren?", "payload": {"options": ["Que no se preocupara demasiado, porque lo que cuenta es cómo reaccionas", "Que bajara en la siguiente parada", "Que llamara otra vez a la empresa"]}, "difficulty": 0.5, "correct_answer": {"value": "Que no se preocupara demasiado, porque lo que cuenta es cómo reaccionas"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Cómo reaccionó el director ante la disculpa de Giulia?", "payload": {"options": ["Se rió y contó que él también había perdido un avión una vez", "Se enfadó mucho por el retraso", "Terminó la entrevista enseguida"]}, "difficulty": 0.5, "correct_answer": {"value": "Se rió y contó que él también había perdido un avión una vez"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Qué pasó dos semanas después de la entrevista?", "payload": {"options": ["Recibió un correo que decía que había sido contratada", "Tuvo que repetir la entrevista", "Decidió no aceptar el trabajo"]}, "difficulty": 0.5, "correct_answer": {"value": "Recibió un correo que decía que había sido contratada"}}]$j$::jsonb),
('00bc3e04-edf4-53e6-b7d9-f884778c1334'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,'B1',2,$p$Die Wohnungsbesichtigung$p$,$p$Lena busca piso en Leipzig y va a una visita que no sale como esperaba.$p$,$p$🔑$p$,$p$Lena lleva semanas buscando piso en Leipzig. Por fin la invitan a una visita, aunque un pequeño malentendido casi lo estropea todo. Lee y escucha su historia.$p$,56,$j$[{"en": "Seit drei Wochen suche ich eine neue Wohnung in Leipzig, weil meine alte zu teuer geworden ist.", "es": "Desde hace tres semanas busco un piso nuevo en Leipzig, porque el antiguo se ha vuelto demasiado caro.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/00bc3e04-edf4-53e6-b7d9-f884778c1334-0.mp3"}, {"en": "Gestern habe ich endlich eine Anzeige gefunden, die perfekt klang: zwei Zimmer, ein Balkon und eine Küche, die schon möbliert war.", "es": "Ayer por fin encontré un anuncio que sonaba perfecto: dos habitaciones, un balcón y una cocina que ya estaba amueblada.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/00bc3e04-edf4-53e6-b7d9-f884778c1334-1.mp3"}, {"en": "Ich rief sofort an und die Vermieterin, die sehr freundlich war, lud mich zu einer Besichtigung ein.", "es": "Llamé enseguida y la casera, que era muy amable, me invitó a una visita.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/00bc3e04-edf4-53e6-b7d9-f884778c1334-2.mp3"}, {"en": "Obwohl ich pünktlich sein wollte, verpasste ich die Straßenbahn, sodass ich zehn Minuten zu spät ankam.", "es": "Aunque quería ser puntual, perdí el tranvía, de modo que llegué diez minutos tarde.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/00bc3e04-edf4-53e6-b7d9-f884778c1334-3.mp3"}, {"en": "«Entschuldigung, ich hätte früher losfahren sollen», sagte ich außer Atem, aber sie lächelte nur und meinte, das sei kein Problem.", "es": "«Perdón, debería haber salido antes», dije sin aliento, pero ella solo sonrió y dijo que no era ningún problema.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/00bc3e04-edf4-53e6-b7d9-f884778c1334-4.mp3"}, {"en": "Die Wohnung, die im vierten Stock liegt, wurde vor einem Jahr renoviert und war heller, als ich erwartet hatte.", "es": "El piso, que está en el cuarto piso, fue renovado hace un año y era más luminoso de lo que yo esperaba.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/00bc3e04-edf4-53e6-b7d9-f884778c1334-5.mp3"}, {"en": "Wenn ich das Geld hätte, würde ich sofort unterschreiben, aber zuerst muss ich mit der Bank sprechen, damit alles sicher ist.", "es": "Si tuviera el dinero, firmaría enseguida, pero primero tengo que hablar con el banco para que todo esté seguro.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/00bc3e04-edf4-53e6-b7d9-f884778c1334-6.mp3"}]$j$::jsonb,$j$[{"word": "die Wohnungsbesichtigung", "translation": "la visita del piso"}, {"word": "die Anzeige", "translation": "el anuncio"}, {"word": "die Vermieterin", "translation": "la casera"}, {"word": "renoviert werden", "translation": "ser renovado"}, {"word": "außer Atem", "translation": "sin aliento"}, {"word": "unterschreiben", "translation": "firmar"}]$j$::jsonb,$j$[{"type": "multiple_choice", "skill": "reading", "prompt": "¿Por qué busca Lena un piso nuevo?", "payload": {"options": ["Porque el antiguo se ha vuelto demasiado caro", "Porque quiere vivir más lejos", "Porque el antiguo es demasiado pequeño"]}, "difficulty": 0.5, "correct_answer": {"value": "Porque el antiguo se ha vuelto demasiado caro"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Qué tenía de especial el piso del anuncio?", "payload": {"options": ["Una cocina que ya estaba amueblada", "Un jardín grande", "Un garaje incluido"]}, "difficulty": 0.5, "correct_answer": {"value": "Una cocina que ya estaba amueblada"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Por qué llegó tarde a la visita?", "payload": {"options": ["Perdió el tranvía", "Se equivocó de dirección", "Se quedó dormida"]}, "difficulty": 0.5, "correct_answer": {"value": "Perdió el tranvía"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Cómo reaccionó la casera ante el retraso?", "payload": {"options": ["Sonrió y dijo que no era problema", "Se enfadó mucho", "Canceló la visita"]}, "difficulty": 0.5, "correct_answer": {"value": "Sonrió y dijo que no era problema"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Qué tiene que hacer Lena antes de firmar?", "payload": {"options": ["Hablar con el banco", "Pintar la cocina", "Buscar otro anuncio"]}, "difficulty": 0.5, "correct_answer": {"value": "Hablar con el banco"}}]$j$::jsonb),
('9cd1913e-c943-5c7b-a3cd-c398da346a37'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,'B1',2,$p$De trein die niet reed$p$,$p$Un plan de fin de semana en Utrecht se tuerce por la lluvia y un tren cancelado.$p$,$p$🚉$p$,$p$Thomas había planeado un día perfecto con una amiga en Utrecht, pero la lluvia y la NS tenían otros planes. Lee y escucha cómo resuelve el imprevisto.$p$,56,$j$[{"en": "Ik had met Lotte afgesproken dat we zaterdag naar de markt in Utrecht zouden gaan.", "es": "Había quedado con Lotte en que el sábado iríamos al mercado de Utrecht.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9cd1913e-c943-5c7b-a3cd-c398da346a37-0.mp3"}, {"en": "Toen ik 's ochtends wakker werd, regende het hard en de lucht die ik door het raam zag, was helemaal grijs.", "es": "Cuando me desperté por la mañana, llovía con fuerza y el cielo que veía por la ventana estaba completamente gris.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9cd1913e-c943-5c7b-a3cd-c398da346a37-1.mp3"}, {"en": "Op het station hoorde ik een omroep: de trein naar Utrecht was door werkzaamheden geannuleerd.", "es": "En la estación oí un aviso: el tren a Utrecht había sido cancelado por obras.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9cd1913e-c943-5c7b-a3cd-c398da346a37-2.mp3"}, {"en": "Hoewel ik behoorlijk teleurgesteld was, belde ik Lotte, omdat we samen een oplossing moesten bedenken.", "es": "Aunque estaba bastante decepcionado, llamé a Lotte, porque teníamos que buscar juntos una solución.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9cd1913e-c943-5c7b-a3cd-c398da346a37-3.mp3"}, {"en": "«Als ik jou was, zou ik gewoon de bus nemen», zei ze lachend, «want die rijdt nog wel.»", "es": "«Yo que tú, cogería sin más el autobús», dijo riendo, «porque ese sí que sigue circulando.»", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9cd1913e-c943-5c7b-a3cd-c398da346a37-4.mp3"}, {"en": "We hebben uiteindelijk de bus genomen en zijn tóch op de markt aangekomen, alleen een uur later dan gepland.", "es": "Al final cogimos el autobús y llegamos igualmente al mercado, solo que una hora más tarde de lo previsto.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9cd1913e-c943-5c7b-a3cd-c398da346a37-5.mp3"}, {"en": "Onder een grote paraplu die Lotte had meegenomen, aten we verse stroopwafels — en de regen kon ons niets meer schelen.", "es": "Bajo un paraguas grande que Lotte había traído, comimos stroopwafels recién hechos, y la lluvia ya nos daba igual.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9cd1913e-c943-5c7b-a3cd-c398da346a37-6.mp3"}]$j$::jsonb,$j$[{"word": "afspreken", "translation": "quedar / acordar"}, {"word": "de werkzaamheden", "translation": "las obras"}, {"word": "geannuleerd", "translation": "cancelado"}, {"word": "teleurgesteld", "translation": "decepcionado"}, {"word": "een oplossing bedenken", "translation": "encontrar una solución"}, {"word": "uiteindelijk", "translation": "al final / finalmente"}]$j$::jsonb,$j$[{"type": "multiple_choice", "skill": "reading", "prompt": "¿Qué habían planeado Thomas y Lotte para el sábado?", "payload": {"options": ["ir al mercado de Utrecht", "ir a la playa", "ir al cine"]}, "difficulty": 0.5, "correct_answer": {"value": "ir al mercado de Utrecht"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Cómo estaba el tiempo por la mañana?", "payload": {"options": ["llovía con fuerza y el cielo estaba gris", "hacía sol", "nevaba"]}, "difficulty": 0.5, "correct_answer": {"value": "llovía con fuerza y el cielo estaba gris"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Por qué se canceló el tren a Utrecht?", "payload": {"options": ["por obras", "por una huelga", "por un accidente"]}, "difficulty": 0.5, "correct_answer": {"value": "por obras"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Qué le aconsejó Lotte por teléfono?", "payload": {"options": ["coger el autobús", "volver a casa", "esperar al siguiente tren"]}, "difficulty": 0.5, "correct_answer": {"value": "coger el autobús"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Qué comieron finalmente en el mercado?", "payload": {"options": ["stroopwafels", "patatas fritas", "queso"]}, "difficulty": 0.5, "correct_answer": {"value": "stroopwafels"}}]$j$::jsonb),
('53e8afb8-17da-588a-a818-7ab8debcbaeb'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B1',2,$p$A entrevista de Rafael$p$,$p$Rafael tiene una entrevista de trabajo, pero un imprevisto en el ônibus le cambia el plan.$p$,$p$💼$p$,$p$Rafael estaba nervioso: tenía la entrevista más importante de su vida. Todo estaba planeado, pero aquella mañana en São Paulo nada salió como esperaba.$p$,56,$j$[{"en": "Rafael tinha uma entrevista de emprego às nove da manhã e estava muito nervoso.", "es": "Rafael tenía una entrevista de trabajo a las nueve de la mañana y estaba muy nervioso.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/53e8afb8-17da-588a-a818-7ab8debcbaeb-0.mp3"}, {"en": "Ele acordou cedo, tomou café e pegou o ônibus que passava perto de casa, como fazia todos os dias.", "es": "Se despertó temprano, desayunó y tomó el autobús que pasaba cerca de casa, como hacía todos los días.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/53e8afb8-17da-588a-a818-7ab8debcbaeb-1.mp3"}, {"en": "No meio do caminho, porém, o ônibus quebrou e todos os passageiros tiveram que descer.", "es": "En medio del camino, sin embargo, el autobús se averió y todos los pasajeros tuvieron que bajar.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/53e8afb8-17da-588a-a818-7ab8debcbaeb-2.mp3"}, {"en": "«Se eu tivesse saído mais cedo, não estaria com esse problema agora», pensou Rafael, olhando o relógio.", "es": "«Si hubiera salido más temprano, no estaría con este problema ahora», pensó Rafael, mirando el reloj.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/53e8afb8-17da-588a-a818-7ab8debcbaeb-3.mp3"}, {"en": "Então ele ligou para a empresa e disse: «Desculpe, gostaria de avisar que vou chegar uns dez minutos atrasado.»", "es": "Entonces llamó a la empresa y dijo: «Disculpe, me gustaría avisar de que voy a llegar unos diez minutos tarde.»", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/53e8afb8-17da-588a-a818-7ab8debcbaeb-4.mp3"}, {"en": "A mulher que atendeu foi muito gentil e respondeu: «Não tem problema, esperamos o senhor. Espero que dê tudo certo!»", "es": "La mujer que atendió fue muy amable y respondió: «No hay problema, lo esperamos. ¡Espero que salga todo bien!»", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/53e8afb8-17da-588a-a818-7ab8debcbaeb-5.mp3"}, {"en": "Rafael pegou um táxi, chegou a tempo e, no fim, conseguiu o emprego que sempre quis.", "es": "Rafael tomó un taxi, llegó a tiempo y, al final, consiguió el trabajo que siempre quiso.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/53e8afb8-17da-588a-a818-7ab8debcbaeb-6.mp3"}]$j$::jsonb,$j$[{"word": "a entrevista de emprego", "translation": "la entrevista de trabajo"}, {"word": "quebrar (o ônibus quebrou)", "translation": "averiarse / romperse"}, {"word": "no meio do caminho", "translation": "a mitad de camino"}, {"word": "avisar", "translation": "avisar"}, {"word": "atrasado", "translation": "tarde / atrasado"}, {"word": "dar tudo certo", "translation": "salir todo bien"}]$j$::jsonb,$j$[{"type": "multiple_choice", "skill": "reading", "prompt": "¿A qué hora era la entrevista de Rafael?", "payload": {"options": ["às nove da manhã", "às oito da manhã", "ao meio-dia"]}, "difficulty": 0.5, "correct_answer": {"value": "às nove da manhã"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Qué imprevisto ocurrió?", "payload": {"options": ["o ônibus quebrou", "ele perdeu o celular", "choveu muito"]}, "difficulty": 0.5, "correct_answer": {"value": "o ônibus quebrou"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Qué pensó Rafael al mirar el reloj?", "payload": {"options": ["que devia ter saído mais cedo", "que ia desistir da entrevista", "que o ônibus era rápido"]}, "difficulty": 0.5, "correct_answer": {"value": "que devia ter saído mais cedo"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Cómo reaccionó la mujer de la empresa?", "payload": {"options": ["foi gentil e disse que esperariam", "ficou brava com o atraso", "desmarcou a entrevista"]}, "difficulty": 0.5, "correct_answer": {"value": "foi gentil e disse que esperariam"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Cómo termina la historia?", "payload": {"options": ["ele conseguiu o emprego", "ele chegou atrasado e perdeu a vaga", "ele voltou para casa"]}, "difficulty": 0.5, "correct_answer": {"value": "ele conseguiu o emprego"}}]$j$::jsonb)
